import shioaji as _sj

_EXPORTS = {
    "StockPosition": "StockPosition",
    "FuturePosition": "FuturePosition",
    "StockPositionDetail": "StockPositionDetail",
    "FuturePositionDetail": "FuturePositionDetail",
    "StockProfitLoss": "StockProfitLoss",
    "FutureProfitLoss": "FutureProfitLoss",
    "StockProfitDetail": "StockProfitDetail",
    "FutureProfitDetail": "FutureProfitDetail",
    "StockProfitLossSummary": "StockProfitLossSummary",
    "FutureProfitLossSummary": "FutureProfitLossSummary",
    "Settlement": "Settlement",
    "SettlementLegacy": "Settlement",
    "SettlementV1": "SettlementV1",
    "AccountBalance": "AccountBalance",
    "Margin": "Margin",
    "TradingLimits": "TradingLimits",
    "ProfitLossTotal": "ProfitLossTotal",
    "ProfitLossSummaryTotal": "ProfitLossSummaryTotal",
    "Unit": "Unit",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.position.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.position' has no attribute {name!r}")
